steps.script:
var m = tree.current_scene
var pos = GameState.get_unit("U_BATTLEWAGON_A")["models"][0]["position"]
return m._find_unit_at_world_pos(Vector2(pos["x"], pos["y"]))

var m = tree.current_scene
var pos = GameState.get_unit("U_BATTLEWAGON_A")["models"][0]["position"]
var world = Vector2(pos["x"], pos["y"])
var screen = m.world_to_screen_position(world)
var ev = InputEventMouseButton.new()
ev.button_index = MOUSE_BUTTON_RIGHT
ev.position = screen
ev.global_position = screen
ev.pressed = true
ev.button_mask = MOUSE_BUTTON_MASK_RIGHT
Input.parse_input_event(ev)
return {"world": [world.x, world.y], "screen": [screen.x, screen.y]}

var m = tree.current_scene
var menu = m._unit_context_menu
if menu == null:
	return "NO_MENU"
var has_header = false
var has_kommandos = false
for i in range(menu.get_item_count()):
	var t = menu.get_item_text(i)
	if t.contains("Embarked Units"):
		has_header = true
	if t.contains("Kommandos"):
		has_kommandos = true
return has_header and has_kommandos

var m = tree.current_scene
var entries = m._get_embarked_menu_entries("U_BATTLEWAGON_B")
var names = []
for e in entries:
	names.append(e["name"])
return names
